 42→func (l *FetchNewsArticlesLogic) FetchNewsArticles(req *types.FetchNewsArticlesReq) (resp *types.FetchNewsArticlesResp, err error) {
 43→	limit := req.Limit
 44→	if limit <= 0 {
 45→		limit = 5
 46→	}
 47→	if limit > 20 {
 48→		limit = 20
 49→	}
 50→
 51→	resp = &types.FetchNewsArticlesResp{
 52→		Articles: make([]string, 0),
 53→		Errors:   make([]string, 0),
 54→	}
 55→
 56→	// 从两个源拉取文章
 57→	var allItems []newsItem
 58→	items36kr, err36kr := fetch36Kr(int(limit))
 59→	if err36kr != nil {
 60→		l.Logger.Infof("FetchNewsArticles fetch_36kr_failed err=%v", err36kr)
 61→		resp.Errors = append(resp.Errors, fmt.Sprintf("36kr: %v", err36kr))
 62→	} else {
 63→		allItems = append(allItems, items36kr...)
 64→	}
 65→
 66→	itemsTencent, errTencent := fetchTencent(int(limit))
 67→	if errTencent != nil {
 68→		l.Logger.Infof("FetchNewsArticles fetch_tencent_failed err=%v", errTencent)
 69→		resp.Errors = append(resp.Errors, fmt.Sprintf("tencent: %v", errTencent))
 70→	} else {
 71→		allItems = append(allItems, itemsTencent...)
 72→	}
 73→
 74→	l.Logger.Infof("FetchNewsArticles 获取到 %d 篇文章（36kr=%d, tencent=%d）", len(allItems), len(items36kr), len(itemsTencent))
 75→
 76→	// 逐篇通过 CrawlURL 保存（CrawlURL 会自动去重和抓取全文）
 77→	for _, item := range allItems {
 78→		if strings.TrimSpace(item.URL) == "" {
 79→			resp.Failed++
 80→			continue
 81→		}
 82→		crawlResp, crawlErr := l.svcCtx.HdAiSearchRpc.CrawlURL(l.ctx, &hd_ai_search.CrawlURLRequest{
 83→			Url:         item.URL,
 84→			PublishTime: item.Time,
 85→		})
 86→		if crawlErr != nil {
 87→			l.Logger.Infof("FetchNewsArticles CrawlURL_failed url=%s err=%v", item.URL, crawlErr)
 88→			resp.Failed++
 89→			resp.Errors = append(resp.Errors, fmt.Sprintf("%s: %v", item.Title, crawlErr))
 90→			continue
 91→		}
 92→		// CrawlURL 返回 article_id，如果是已有记录也会返回
 93→		if crawlResp != nil && crawlResp.ArticleId > 0 {
 94→			resp.Fetched++
 95→			resp.Articles = append(resp.Articles, item.Title)
 96→		} else {
 97→			resp.Skipped++
 98→		}
 99→	}
100→
101→	return resp, nil
102→}
