 32→func (l *ChatImHotArticleListLogic) ChatImHotArticleList(req *types.ChatImHotArticleListReq) (resp *types.ChatImHotArticleListResp, err error) {
 33→	if err := l.paramsValidate(req); err != nil {
 34→		l.Logger.Errorf("ChatImHotArticleList paramsValidate_failed req=%+v err=%v", req, err)
 35→		return nil, err
 36→	}
 37→
 38→	tokenInfo, err := auth_token.GetTokenInfo(l.ctx)
 39→	if err != nil {
 40→		l.Logger.Errorf("ChatImHotArticleList GetTokenInfo_failed req=%+v err=%v", req, err)
 41→		return nil, err
 42→	}
 43→	if tokenInfo == nil || strings.TrimSpace(tokenInfo.UserId) == "" {
 44→		err = hderror.NewErrorMsg(hderror_code.FAIL, "ChatImHotArticleList 获取用户信息失败")
 45→		l.Logger.Errorf("ChatImHotArticleList token_empty req=%+v err=%v", req, err)
 46→		return nil, err
 47→	}
 48→
 49→	pageNo := req.PageNo
 50→	if pageNo < 0 {
 51→		pageNo = 0
 52→	}
 53→	pageSize := req.PageSize
 54→	if pageSize <= 0 {
 55→		pageSize = 20
 56→	}
 57→
 58→	rpcReq := &hd_ai_search.GetImHotArticleListRequest{UserId: strings.TrimSpace(tokenInfo.UserId)}
 59→	hd_struct_util.Copy(rpcReq, req)
 60→	rpcReq.PageNo = pageNo
 61→	rpcReq.PageSize = pageSize
 62→
 63→	rpcResp, err := l.svcCtx.HdAiSearchRpc.GetImHotArticleList(l.ctx, rpcReq)
 64→	if err != nil {
 65→		l.Logger.Errorf("ChatImHotArticleList GetImHotArticleList_failed req=%+v user_id=%s err=%v", req, tokenInfo.UserId, err)
 66→		return nil, err
 67→	}
 68→
 69→	resp = &types.ChatImHotArticleListResp{
 70→		ArticleList: make([]types.ChatImHotArticleItem, 0, len(rpcResp.ArticleList)),
 71→		Total:       rpcResp.Total,
 72→	}
 73→	for _, item := range rpcResp.ArticleList {
 74→		if item == nil {
 75→			continue
 76→		}
 77→		resp.ArticleList = append(resp.ArticleList, types.ChatImHotArticleItem{
 78→			HotArticleId:   item.HotArticleId,
 79→			ArticleTitle:   item.ArticleTitle,
 80→			ArticleSummary: item.ArticleSummary,
 81→			ArticleSource:  item.ArticleSource,
 82→			ArticleAuthor:  item.ArticleAuthor,
 83→			ActionType:     item.ActionType,
 84→			PublishTime:    item.PublishTime,
 85→			ArticleIcon:    item.ArticleIcon,
 86→		})
 87→	}
 88→	return resp, nil
 89→
 90→}
